B.aj5=new A.fc("Quem somos","O 360Fit \xe9 uma plataforma de gest\xe3o fitness, sa\xfade e performance que conecta academias, personal trainers, nutricionistas, fisioterapeutas e seus alunos.\n\nContato do controlador de dados: contatoflorestaja@hotmail.com \xb7 (87) 99971-0850.")
B.ajb=new A.fc("Dados que coletamos","\u2022 Cadastro (nome, email, telefone) \u2014 criar e autenticar a sua conta.\n\u2022 Perfil f\xedsico (idade, peso, medidas, objetivo) \u2014 acompanhamento do treino.\n\u2022 Dados de sa\xfade (avalia\xe7\xf5es f\xedsicas, restri\xe7\xf5es) \u2014 prescri\xe7\xe3o segura; s\xe3o dados sens\xedveis pela LGPD, tratados com o seu consentimento e vis\xedveis apenas a voc\xea, ao profissional respons\xe1vel e ao administrador da sua empresa.\n\u2022 Uso do app (treinos realizados, frequ\xeancia, agendamentos).\n\u2022 Mensagens trocadas com o seu profissional.")
B.aj8=new A.fc("O que N\xc3O fazemos","N\xe3o vendemos seus dados, n\xe3o os compartilhamos para publicidade e n\xe3o usamos seus dados de sa\xfade para nada al\xe9m do acompanhamento contratado.")
B.aj2=new A.fc("Compartilhamento","Seus dados s\xe3o vis\xedveis apenas dentro do ambiente da empresa \xe0 qual voc\xea est\xe1 vinculado, conforme o papel de cada usu\xe1rio. Usamos a infraestrutura Supabase (banco de dados e autentica\xe7\xe3o) com isolamento por empresa e criptografia em tr\xe2nsito.")
B.ajd=new A.fc("Reten\xe7\xe3o e exclus\xe3o","Mantemos seus dados enquanto a conta estiver ativa. Voc\xea pode excluir a conta e todos os dados pelo app (Mais \u2192 Excluir minha conta) ou pelo email contatoflorestaja@hotmail.com. O processo \xe9 conclu\xeddo em at\xe9 30 dias.")
B.aj4=new A.fc("Seus direitos (LGPD)","A qualquer momento voc\xea pode acessar, corrigir, portar ou eliminar seus dados e revogar consentimentos \u2014 basta contatar contatoflorestaja@hotmail.com.")
B.aj0=new A.fc("Menores de idade","O app n\xe3o \xe9 destinado a menores de 13 anos. Entre 13 e 18 anos, o cadastro deve ser autorizado por respons\xe1vel legal junto \xe0 academia/cl\xednica.")
B.aj9=new A.fc("Seguran\xe7a","Controle de acesso por papel e por empresa (Row Level Security), criptografia em tr\xe2nsito (TLS) e autentica\xe7\xe3o segura. Em caso de incidente relevante, comunicaremos os afetados e a ANPD conforme a LGPD.")
B.aiX=new A.fc("Permiss\xf5es do aplicativo","C\xe2mera/galeria (foto de perfil e avalia\xe7\xf5es, somente quando voc\xea optar) e notifica\xe7\xf5es (lembretes de treino e agendamentos).")
B.aj1=new A.fc("Contato","D\xfavidas sobre privacidade: contatoflorestaja@hotmail.com \xb7 (87) 99971-0850.")
B.a7t=s([B.aj5,B.ajb,B.aj8,B.aj2,B.ajd,B.aj4,B.aj0,B.aj9,B.aiX,B.aj1],t.SV)
B.VW=new A.We("Pol\xedtica de Privacidade",B.a7t)
B.vf=new A.GY(B.VW,null)
B.aiY=new A.fc("Aceita\xe7\xe3o","Ao criar uma conta ou usar o 360Fit voc\xea concorda com estes Termos e com a Pol\xedtica de Privacidade.")
B.aj7=new A.fc("O servi\xe7o","Plataforma SaaS de gest\xe3o fitness: prescri\xe7\xe3o e acompanhamento de treinos, avalia\xe7\xf5es f\xedsicas, agenda, comunica\xe7\xe3o profissional\u2013aluno e m\xf3dulos administrativos, conforme o plano contratado (Basic, Pro ou Premium).")
B.aj3=new A.fc("Contas e responsabilidades","As credenciais s\xe3o pessoais e intransfer\xedveis. Profissionais declaram possuir habilita\xe7\xe3o v\xe1lida (CREF, CRN, CREFITO etc.). A empresa contratante \xe9 respons\xe1vel pelos v\xednculos com seus alunos e profissionais.")
B.aiZ=new A.fc("Aviso importante de sa\xfade","O 360Fit \xe9 uma ferramenta de gest\xe3o \u2014 n\xe3o presta aconselhamento m\xe9dico. Treinos e orienta\xe7\xf5es s\xe3o de responsabilidade do profissional habilitado. Consulte um m\xe9dico antes de iniciar exerc\xedcios; em caso de dor ou mal-estar, interrompa a atividade e procure atendimento.")
B.aj_=new A.fc("Assinaturas e cancelamento","Planos com cobran\xe7a recorrente. O cancelamento interrompe as cobran\xe7as seguintes e o acesso permanece at\xe9 o fim do per\xedodo pago.")
B.ajc=new A.fc("Uso aceit\xe1vel","\xc9 proibido usar a plataforma para fins il\xedcitos, tentar acessar dados de outras empresas ou usu\xe1rios, fazer engenharia reversa ou publicar conte\xfado ofensivo.")
B.aj6=new A.fc("Limita\xe7\xe3o de responsabilidade",'O servi\xe7o \xe9 fornecido "como est\xe1", podendo passar por manuten\xe7\xf5es. Na m\xe1xima extens\xe3o legal, a responsabilidade limita-se aos valores pagos nos 12 meses anteriores.')
B.aja=new A.fc("Foro e contato","Lei brasileira; foro da comarca do domic\xedlio do consumidor. Contato: contatoflorestaja@hotmail.com \xb7 (87) 99971-0850.")
B.a7Y=s([B.aiY,B.aj7,B.aj3,B.aiZ,B.aj_,B.ajc,B.aj6,B.aja],t.SV)
